import{_ as i,o as e,c as a,ag as t}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/quickstart.md","filePath":"en/guide/quickstart.md","lastUpdated":null}'),n={name:"en/guide/quickstart.md"};function l(p,s,r,o,h,k){return e(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><p>This guide will help you get started with AI programming core concepts in 5 minutes.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Basic programming knowledge (any language)</li><li>Basic understanding of AI programming assistants (e.g., Claude Code, Cursor)</li><li>Node.js 18+ installed (if learning OpenSpec)</li></ul><h2 id="_1-understand-core-concepts" tabindex="-1">1. Understand Core Concepts <a class="header-anchor" href="#_1-understand-core-concepts" aria-label="Permalink to &quot;1. Understand Core Concepts&quot;">​</a></h2><p>Before starting, let&#39;s quickly understand the three core concepts:</p><h3 id="what-is-a-skill" tabindex="-1">What is a Skill? <a class="header-anchor" href="#what-is-a-skill" aria-label="Permalink to &quot;What is a Skill?&quot;">​</a></h3><p>A Skill is a <strong>reusable AI instruction template</strong>. It tells the AI assistant how to complete a specific task, including:</p><ul><li><strong>name</strong>: Skill name</li><li><strong>description</strong>: Function description</li><li><strong>prompt</strong>: Detailed execution instructions</li><li><strong>examples</strong>: Input/output examples</li></ul><p><strong>One-sentence summary</strong>: Skill = Standardized work manual for AI</p><h3 id="what-is-openspec" tabindex="-1">What is OpenSpec? <a class="header-anchor" href="#what-is-openspec" aria-label="Permalink to &quot;What is OpenSpec?&quot;">​</a></h3><p>OpenSpec is a <strong>Spec-Driven Development (SDD)</strong> framework. Core idea:</p><blockquote><p>Define specifications before writing code. Ensure humans and AI agree on requirements.</p></blockquote><p><strong>Workflow</strong>:</p><ol><li><code>/opsx:propose</code> - Create proposal</li><li><code>/opsx:apply</code> - Apply specifications, AI implements code</li><li><code>/opsx:archive</code> - Archive completion</li></ol><h3 id="what-is-harness" tabindex="-1">What is Harness? <a class="header-anchor" href="#what-is-harness" aria-label="Permalink to &quot;What is Harness?&quot;">​</a></h3><p>Harness is a <strong>testing infrastructure</strong> for evaluating AI output quality:</p><ul><li><strong>Test Scenarios</strong>: Define inputs and expected outputs</li><li><strong>Evaluators</strong>: Automated evaluation of AI outputs</li><li><strong>Mock Server</strong>: Test environment without real API calls</li></ul><h2 id="_2-create-your-first-skill" tabindex="-1">2. Create Your First Skill <a class="header-anchor" href="#_2-create-your-first-skill" aria-label="Permalink to &quot;2. Create Your First Skill&quot;">​</a></h2><p>Create a simple code explanation Skill:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;explain-code&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Explain how code works with detailed analysis&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;prompt&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Please explain how the following code works:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1. Overall functionality</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">2. Key variables and functions</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">3. Execution flow</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">4. Potential optimization suggestions</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Code:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">{{code}}&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;examples&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;input&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;def fib(n):</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    if n &lt;= 1:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        return n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    return fib(n-1) + fib(n-2)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;output&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;This is a recursive Fibonacci function implementation...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Save the file as <code>explain-code.json</code> in your project&#39;s <code>.skills/</code> directory.</p><h2 id="_3-experience-openspec-workflow" tabindex="-1">3. Experience OpenSpec Workflow <a class="header-anchor" href="#_3-experience-openspec-workflow" aria-label="Permalink to &quot;3. Experience OpenSpec Workflow&quot;">​</a></h2><p>Install OpenSpec CLI:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @fission-ai/openspec@latest</span></span></code></pre></div><p>Initialize project:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> your-project</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openspec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span></span></code></pre></div><p>Create your first change:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/opsx:propose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Add user login feature&quot;</span></span></code></pre></div><p>AI will generate:</p><ul><li><code>proposal.md</code> - Proposal description</li><li><code>design.md</code> - Technical design</li><li><code>specs/</code> - Detailed requirements</li><li><code>tasks.md</code> - Implementation tasks</li></ul><p>After review and confirmation, let AI implement:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/opsx:apply</span></span></code></pre></div><h2 id="_4-next-steps" tabindex="-1">4. Next Steps <a class="header-anchor" href="#_4-next-steps" aria-label="Permalink to &quot;4. Next Steps&quot;">​</a></h2><p>Congratulations! You&#39;ve learned the three core paradigms of AI programming. Next:</p><ul><li>📖 Deep dive into <a href="/en/guide/skills/what-is-skill">Skills Tutorial</a></li><li>📋 Master <a href="/en/guide/openspec/concepts">OpenSpec Spec-Driven Development</a></li><li>🧪 Learn <a href="/en/guide/harness/intro">Harness Testing Infrastructure</a></li><li>🚀 Practice with <a href="/examples/">Example Projects</a></li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><p><strong>Q: Which one should I learn first?</strong></p><p>A: Suggested order: Skill → OpenSpec → Harness. Skill is the foundation, OpenSpec is the workflow, Harness is quality assurance.</p><p><strong>Q: Do these tools depend on a specific AI?</strong></p><p>A: No. Skills are a universal format, OpenSpec and Harness are decoupled from specific AI tools. You can use them in any tool that supports these formats.</p><p><strong>Q: Is the learning curve steep?</strong></p><p>A: Getting started is easy! You can create your first Skill in 5 minutes. Going deep requires practice, but there&#39;s a clear learning path at every step.</p>`,43)])])}const u=i(n,[["render",l]]);export{c as __pageData,u as default};
